// RegisterRerankerBackend registers a RerankerBackend implementation with the C runtime.
func RegisterRerankerBackend(impl RerankerBackend) error {
	bridge := NewRerankerBackendBridge(impl)
	handle := cgo.NewHandle(bridge)
	// Build the C vtable by calling the C helper function.
	// This ensures function pointers are correctly populated in C, fixing ARM64 macOS issues.
	vtable := C.kreuzberg_reranker_backend_vtable_new()
	if vtable == nil {
		return fmt.Errorf("failed to allocate %s vtable", impl.Name())
	}
	defer C.free(unsafe.Pointer(vtable))
	// Call C registration
	cName := C.CString(impl.Name())
	defer C.free(unsafe.Pointer(cName))

	var cErr *C.char
	rc := C.kreuzberg_register_reranker_backend(
		cName,
		vtable,
		unsafe.Pointer(uintptr(handle)),
		&cErr,
	)

	if rc != 0 {
		msg := "failed to register RerankerBackend"
		if cErr != nil {
			msg = C.GoString(cErr)
			C.kreuzberg_free_string(cErr)
		}
		handle.Delete()
		return fmt.Errorf("%s", msg)
	}

	// Store handle by name for later cleanup on unregister
	reranker_backendRegistry.store(impl.Name(), handle)
	return nil
}

// UnregisterRerankerBackend unregisters a RerankerBackend implementation.
func UnregisterRerankerBackend(name string) error {
	cName := C.CString(name)
	defer C.free(unsafe.Pointer(cName))
	var cErr *C.char
	rc := C.kreuzberg_unregister_reranker_backend(cName, &cErr)

	if rc != 0 {
	msg := "failed to unregister RerankerBackend"
	if cErr != nil {
		msg = C.GoString(cErr)
		C.kreuzberg_free_string(cErr)
	}
	return fmt.Errorf("%s", msg)
	}

	// Delete the handle now that Rust has unregistered the plugin
	reranker_backendRegistry.delete(name)
	return nil
}

// ClearRerankerBackends removes all registered RerankerBackend implementations.
func ClearRerankerBackends() error {
	var cErr *C.char
	rc := C.kreuzberg_clear_reranker_backend(&cErr)

	if rc != 0 {
		msg := "failed to clear RerankerBackend plugins"
		if cErr != nil {
			msg = C.GoString(cErr)
			C.free(unsafe.Pointer(cErr))
		}
		return fmt.Errorf("%s", msg)
	}

	// Delete all handles now that Rust has cleared all plugins
	reranker_backendRegistry.clear()
	return nil
}
